#!/usr/bin/env python3
"""Standalone ScoreDVI runner that bundles the original project code."""

from __future__ import annotations

import argparse
import base64
import io
import importlib
import os
import sys
import tempfile
import zipfile
from pathlib import Path
from typing import Optional

import numpy as np
import torch
from PIL import Image

THIS_DIR = Path(__file__).resolve().parent
DEFAULT_MODEL_DIR = THIS_DIR / "pretrained_models" / "score_dvi"

SCOREDVI_ARCHIVE_B64 = """

"""

_BUNDLE_PATH: Optional[Path] = None


def _ensure_bundle() -> Path:
    global _BUNDLE_PATH
    if _BUNDLE_PATH and _BUNDLE_PATH.exists():
        return _BUNDLE_PATH
    target_dir = Path(tempfile.mkdtemp(prefix="scoredvi_bundle_"))
    data = base64.b64decode(SCOREDVI_ARCHIVE_B64)
    with zipfile.ZipFile(io.BytesIO(data)) as zf:
        zf.extractall(target_dir)
    sys.path.insert(0, str(target_dir))
    _BUNDLE_PATH = target_dir
    return target_dir


def _device_to_gpu_env(device: str) -> str:
    if device.isdigit():
        return device
    if device.startswith("cuda"):
        if ":" in device:
            idx = device.split(":", 1)[1]
            return idx or "0"
        return "0"
    raise RuntimeError(
        "ScoreDVI only supports CUDA GPUs; received device spec '{device}'".format(device=device)
    )


def _load_scoredvi_module(device: str, model_path: Path, lam: float, gmm: int):
    _ensure_bundle()
    os.environ["SCOREDVI_DEVICE"] = device
    os.environ["SCOREDVI_MODEL_PATH"] = str(model_path)
    os.environ["SCOREDVI_LAM"] = str(lam)
    os.environ["SCOREDVI_GMM"] = str(gmm)
    os.environ["SCOREDVI_GPU_DEVICES"] = _device_to_gpu_env(device)
    if "ScoreDVI" in sys.modules:
        return importlib.reload(sys.modules["ScoreDVI"])
    return importlib.import_module("ScoreDVI")


def _read_image(path: Path) -> Image.Image:
    if not path.exists():
        raise FileNotFoundError(f"Input image does not exist: {path}")
    return Image.open(path).convert("RGB")


def _save_image(array: np.ndarray, path: Path) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    Image.fromarray((np.clip(array, 0, 1) * 255.0).astype(np.uint8), mode="RGB").save(path)


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Run ScoreDVI denoising on a single sRGB image.")
    parser.add_argument("--input", required=True, help="Path to the noisy sRGB image")
    parser.add_argument("--output", required=True, help="Where to save the denoised image")
    parser.add_argument("--reference", help="Optional clean reference image to compute PSNR/SSIM")
    parser.add_argument("--device", default=None, help="Device spec such as 'cuda:0' or 'cpu'")
    parser.add_argument("--steps", type=int, default=400, help="Total optimization steps (default 400)")
    parser.add_argument("--lr", type=float, default=1e-3, help="Learning rate (default 1e-3)")
    parser.add_argument("--lam", type=float, default=0.5, help="Prior weight lambda")
    parser.add_argument("--alpha0", type=float, default=1.0, help="Alpha0 hyperparameter")
    parser.add_argument("--beta0", type=float, default=0.02, help="Beta0 hyperparameter")
    parser.add_argument("--exp-weight", type=float, default=0.9, help="EMA smoothing factor")
    parser.add_argument("--gmm", type=int, default=3, help="Number of Gaussian mixture components")
    parser.add_argument("--model-dir", default=str(DEFAULT_MODEL_DIR), help="Directory containing ScoreDVI model*.pth files")
    parser.add_argument("--second-pass-threshold", type=float, default=0.05, help="Sigma threshold that triggers a second refinement run")
    return parser.parse_args()


def run_single_image(args: argparse.Namespace) -> None:
    input_path = Path(args.input).expanduser().resolve()
    output_path = Path(args.output).expanduser().resolve()
    model_path = Path(args.model_dir).expanduser().resolve()
    device = args.device or ("cuda" if torch.cuda.is_available() else "cpu")
    if not device.startswith("cuda"):
        raise RuntimeError(
            "ScoreDVI currently requires a CUDA-capable GPU; detected device spec '{device}'.".format(
                device=device
            )
        )

    module = _load_scoredvi_module(device, model_path, args.lam, args.gmm)
    pil_to_np = module.pil_to_np

    noisy = _read_image(input_path)
    noisy_np = pil_to_np(noisy)

    if args.reference:
        reference_np = pil_to_np(_read_image(Path(args.reference).expanduser().resolve()))
    else:
        reference_np = noisy_np

    kwargs = dict(
        LR=args.lr,
        a0=args.alpha0,
        b0=args.beta0,
        exp_weight=args.exp_weight,
        lam=args.lam,
        GMM_num=args.gmm,
        total_step=args.steps,
        model_path=str(model_path),
    )

    def _run_once(noisy_arr):
        return module.denoising(noisy_arr, reference_np, **kwargs)

    psnr, ssim, denoised, sigma_mean = _run_once(noisy_np)
    if sigma_mean > args.second_pass_threshold:
        psnr, ssim, denoised, _ = _run_once(noisy_np)

    _save_image(denoised, output_path)

    if args.reference:
        print(f"PSNR: {psnr:.4f} dB, SSIM: {ssim:.4f}")
    else:
        print("Reference image not provided; skipping PSNR/SSIM computation.")


def main() -> None:
    args = parse_args()
    run_single_image(args)


if __name__ == "__main__":
    main()
